      await userService.createUser('audituser', 'AuditPass123!!', 'Dispatcher', 'admin')
      const log = await db.auditLogs.where('action').equals('USER_CREATED').first()
      expect(log).toBeTruthy()
      expect(log?.actor).toBe('admin')
