```typescript
async deliver(notificationId): Promise<void> {
  // On failure: writes nextRetryAt (30s/60s/120s backoff) to IndexedDB, status stays Pending
  // NO window.setTimeout
}
async processRetryQueue(): Promise<void> {
  const now = Date.now()
  const pending = await db.notifications.where('status').equals('Pending').toArray()
  for (const item of pending) {
    if (item.id && (!item.nextRetryAt || item.nextRetryAt <= now)) {
