async function loginAs(page: import('@playwright/test').Page, username: string, password: string) {
  await page.goto('/login')
  await page.getByLabel('Username').fill(username)
  await page.getByLabel('Password').fill(password)
  await page.getByRole('button', { name: 'Sign In' }).click()
  await expect(page.getByRole('heading', { name: 'Dashboard' })).toBeVisible()
}

// Fish RBAC: only ContentEditor, ContentReviewer, Administrator see non-published entries

test('member fish list shows only published entries', async ({ page }) => {
  await loginAs(page, 'member', 'HarborMember1!')
  await page.goto('/fish')
  // Status filter should not be visible to member (editorial-only control)
  await expect(page.getByLabel(/status/i)).not.toBeVisible()
})

test('content editor fish list shows status filter', async ({ page }) => {
  await loginAs(page, 'editor', 'HarborEdit#1!')
  await page.goto('/fish')
  await expect(page.getByLabel(/status/i)).toBeVisible()
})

test('member cannot view a draft fish entry by direct URL', async ({ page }) => {
  // Log in as editor, create a draft fish entry, capture its ID, then switch to member
  await loginAs(page, 'editor', 'HarborEdit#1!')
  await page.goto('/fish/new')
  await page.getByLabel(/name/i).fill('Secret Draft Fish')
  await page.getByLabel(/slug/i).fill('secret-draft-fish')
  // Fill required description field if present
  const descField = page.getByLabel(/description/i)
  if (await descField.isVisible()) {
    await descField.fill('Draft description')
  }
  await page.getByRole('button', { name: /save|create|submit/i }).first().click()
  // Wait for navigation to fish detail page
  await page.waitForURL(/\/fish\/\d+/)
  const fishUrl = page.url()

  // Now log out and log in as member
  await page.getByRole('button', { name: 'Logout' }).click()
  await expect(page).toHaveURL(/\/login/)

  await loginAs(page, 'member', 'HarborMember1!')
  await page.goto(fishUrl)

  // Member should see "not found" text, not the fish content
  await expect(page.getByText(/not found/i)).toBeVisible()
  await expect(page.getByText('Secret Draft Fish')).not.toBeVisible()
})

test('member cannot see Workflow tab on any fish detail page', async ({ page }) => {
  // Log in as editor, create and publish a fish entry
  await loginAs(page, 'editor', 'HarborEdit#1!')
  await page.goto('/fish/new')
  await page.getByLabel(/name/i).fill('Published Fish Test')
  await page.getByLabel(/slug/i).fill('published-fish-test')
  const descField = page.getByLabel(/description/i)
  if (await descField.isVisible()) {
    await descField.fill('Published description')
  }
  await page.getByRole('button', { name: /save|create|submit/i }).first().click()
  await page.waitForURL(/\/fish\/\d+/)
  const fishUrl = page.url()

  // Submit for review and approve to publish
  const workflowTab = page.getByRole('tab', { name: /workflow/i })
  if (await workflowTab.isVisible()) {
    await workflowTab.click()
    const submitBtn = page.getByRole('button', { name: /submit.*review|request.*review/i })
    if (await submitBtn.isVisible()) {
      await submitBtn.click()
    }
  }

  // Log out and log back in as member
  await page.getByRole('button', { name: 'Logout' }).click()
  await loginAs(page, 'member', 'HarborMember1!')
  await page.goto(fishUrl)

  // Member should not see the Workflow tab even on an accessible entry
  await expect(page.getByRole('tab', { name: /workflow/i })).not.toBeVisible()
  await expect(page.getByRole('tab', { name: /version history/i })).not.toBeVisible()
})

test('admin can see all fish entries including drafts', async ({ page }) => {
  await loginAs(page, 'admin', 'HarborAdmin#1!')
  await page.goto('/fish')
  await expect(page.getByLabel(/status/i)).toBeVisible()
})

test('dispatcher cannot access fish/new (editor+admin only)', async ({ page }) => {
  await loginAs(page, 'dispatcher', 'HarborDisp#1!')
  await page.goto('/fish/new')
  await expect(page.getByText(/forbidden/i)).toBeVisible()
})
"}

