15	export type AuthErrorCode =
16	  | 'AUTH_USER_NOT_FOUND'
17	  | 'AUTH_WRONG_PASSWORD'
18	  | 'AUTH_LOCKED'
19	  | 'AUTH_SESSION_EXPIRED'
