1	import { db } from '../db/db.ts'
2	import type { User, UserRole } from '../types/index.ts'
3	import {
4	  decryptField,
5	  deriveEncryptionKey,
6	  encryptField,
7	  verifyPassword,
8	} from './cryptoService.ts'
9	
10	const SESSION_KEY = 'hf_session'
11	const MAX_FAILED_ATTEMPTS = 5
12	const LOCK_DURATION_MS = 15 * 60 * 1000
13	const SESSION_MAX_AGE_MS = 8 * 60 * 60 * 1000
14	
15	export type AuthErrorCode =
16	  | 'AUTH_USER_NOT_FOUND'
17	  | 'AUTH_WRONG_PASSWORD'
18	  | 'AUTH_LOCKED'
19	  | 'AUTH_SESSION_EXPIRED'
20	
21	export class AuthError extends Error {
22	  code: AuthErrorCode
23	  remainingMs?: number
24	
25	  constructor(code: AuthErrorCode, message: string, remainingMs?: number) {
26	    super(message)
27	    this.code = code
28	    this.remainingMs = remainingMs
29	  }
30	}
31	
32	interface StoredSession {
33	  sessionId: number
34	  userId: number
35	  role: UserRole
36	}
37	
38	interface LoginResult {
39	  user: User
40	  encryptionKey: CryptoKey
41	}
42	
43	function saveStoredSession(session: StoredSession) {
44	  localStorage.setItem(SESSION_KEY, JSON.stringify(session))
45	}
46	
47	function readStoredSession(): StoredSession | null {
48	  const raw = localStorage.getItem(SESSION_KEY)
49	  if (!raw) {
50	    return null
51	  }
52	
53	  try {
54	    const parsed = JSON.parse(raw) as StoredSession
55	    if (!parsed.sessionId || !parsed.userId || !parsed.role) {
56	      localStorage.removeItem(SESSION_KEY)
57	      return null
58	    }
59	    return parsed
60	  } catch {
61	    localStorage.removeItem(SESSION_KEY)
62	    return null
63	  }
64	}
65	
66	async function incrementFailures(user: User) {
67	  if (!user.id) {
68	    return
69	  }
70	
71	  const nextAttempts = user.failedAttempts + 1
72	  if (nextAttempts >= MAX_FAILED_ATTEMPTS) {
73	    await db.users.update(user.id, {
74	      failedAttempts: 0,
75	      lockedUntil: Date.now() + LOCK_DURATION_MS,
76	    })
77	    return
78	  }
79	
80	  await db.users.update(user.id, { failedAttempts: nextAttempts })
81	}
82	
83	export const authService = {
84	  async login(username: string, password: string): Promise<LoginResult> {
85	    const user = await db.users.where('username').equals(username.trim()).first()
86	    if (!user || !user.id) {
87	      throw new AuthError('AUTH_USER_NOT_FOUND', 'Invalid username or password.')
88	    }
89	
90	    const now = Date.now()
91	    if (user.lockedUntil && user.lockedUntil > now) {
92	      throw new AuthError('AUTH_LOCKED', 'Account is locked.', user.lockedUntil - now)
93	    }
94	
95	    const validPassword = await verifyPassword(password, user.passwordHash, user.salt)
96	    if (!validPassword) {
97	      await incrementFailures(user)
98	      throw new AuthError('AUTH_WRONG_PASSWORD', 'Invalid username or password.')
99	    }
100	
101	    await db.users.update(user.id, {
102	      failedAttempts: 0,
103	      lockedUntil: undefined,
104	    })
105	
106	    const nowMs = Date.now()
107	    const sessionId = await db.sessions.add({
108	      userId: user.id,
109	      createdAt: nowMs,
110	      lastActiveAt: nowMs,
111	    })
112	
113	    saveStoredSession({ sessionId, userId: user.id, role: user.role })
114	
115	    const refreshedUser = await db.users.get(user.id)
116	    if (!refreshedUser) {
117	      throw new AuthError('AUTH_USER_NOT_FOUND', 'Invalid username or password.')
118	    }
119	
120	    const encryptionKey = await deriveEncryptionKey(password, refreshedUser.salt)
121	    return {
122	      user: refreshedUser,
123	      encryptionKey,
124	    }
125	  },
126	
127	  logout() {
128	    localStorage.removeItem(SESSION_KEY)
129	  },
130	
131	  async restoreSession(): Promise<User | null> {
132	    const saved = readStoredSession()
133	    if (!saved) {
134	      return null
135	    }
136	
137	    const session = await db.sessions.get(saved.sessionId)
138	    if (!session) {
139	      localStorage.removeItem(SESSION_KEY)
140	      return null
141	    }
142	
143	    const now = Date.now()
144	    if (now - session.lastActiveAt > SESSION_MAX_AGE_MS) {
145	      await db.sessions.delete(saved.sessionId)
146	      localStorage.removeItem(SESSION_KEY)
147	      throw new AuthError('AUTH_SESSION_EXPIRED', 'Session expired.')
148	    }
149	
150	    await db.sessions.update(saved.sessionId, {
151	      lastActiveAt: now,
152	    })
153	
154	    const user = await db.users.get(saved.userId)
155	    if (!user) {
156	      localStorage.removeItem(SESSION_KEY)
157	      return null
158	    }
159	
160	    return user
161	  },
162	
163	  async updateSensitiveNotes(userId: number, notes: string, key: CryptoKey): Promise<void> {
164	    const encryptedNotes = await encryptField(notes, key)
165	    await db.users.update(userId, { sensitiveNotes: encryptedNotes })
166	  },
167	
168	  async readSensitiveNotes(userId: number, key: CryptoKey): Promise<string | null> {
169	    const user = await db.users.get(userId)
170	    if (!user || !user.sensitiveNotes) {
171	      return null
172	    }
173	    return decryptField(user.sensitiveNotes, key)
174	  },
175	}
